function formatUserName(firstName, lastName, title) {
  // Обрезаем и защищаемся от null/undefined
  const parts = [title, firstName, lastName]
    .map(part => (part ?? '').trim())
    .filter(part => part.length > 0);

  if (parts.length === 0) return 'Аноним';

  return parts.join(' ');
}

// Или с шаблонным литералом для двух обязательных частей:
function formatUserName(firstName, lastName, title = '') {
  const name = [firstName, lastName]
    .map(s => (s ?? '').trim())
    .filter(Boolean)
    .join(' ');

  if (!name) return 'Аноним';
  return title.trim() ? `${title.trim()} ${name}` : name;
}
